seed_files.textprocessor/utils.py:
"""Shared utility functions for textprocessor.

These helpers are used across multiple modules and handle common
edge cases like type coercion and length constraints.
"""


def ensure_string(value) -> str:
    """Coerce a value to a string.

    If the value is already a string it is returned unchanged.
    Bytes are decoded as UTF-8.  None becomes the empty string.
    Everything else is converted via str().

    Examples:
        >>> ensure_string("hello")
        'hello'
        >>> ensure_string(42)
        '42'
        >>> ensure_string(None)
        ''
        >>> ensure_string(b"bytes")
        'bytes'
    """
    if isinstance(value, str):
        return value
    if value is None:
        return ""
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="replace")
    return str(value)


def truncate(text: str, max_length: int, suffix: str = "") -> str:
    """Truncate *text* to at most *max_length* characters.

    If the text is longer than *max_length* the *suffix* (default empty)
    is appended so the total length equals *max_length*.
    """
    if len(text) <= max_length:
        return text
    if suffix:
        return text[: max_length - len(suffix)] + suffix
    return text[:max_length]


def count_words(text: str) -> int:
    """Return the number of whitespace-delimited words in *text*."""
    return len(text.split())


def is_blank(text: str) -> bool:
    """Return True if *text* is empty or contains only whitespace."""
    return not text or text.isspace()
